using System;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    /// <summary>
    /// AOT-compatible converter for <see cref="ResponseError"/>.
    /// The built-in converter in Azure.Core is internal and cannot be used by the source generator.
    /// </summary>
    internal class AotResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var doc = JsonDocument.ParseValue(ref reader);
            var el = doc.RootElement;
            string code = el.TryGetProperty("code", out var c) ? c.GetString() : null;
            string message = el.TryGetProperty("message", out var m) ? m.GetString() : null;
            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code", value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message", value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

